     1→/**
     2→ * MMS Store
     3→ *
     4→ * Central state management using @belt/tools machines.
     5→ * This replaces React hooks (useState, useEffect) and zustand per project constraints.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4
     8→ * @see README.md for @belt/tools API reference
     9→ */
    10→
    11→import { createMachine } from '@belt/tools';
    12→
    13→import {
    14→  fleetSlice,
    15→  fleetAsyncSlice,
    16→  canvasSlice,
    17→  canvasDataSlice,
    18→  pmSlice,
    19→  pmAsyncSlice,
    20→  scenarioSlice,
    21→  scenarioAsyncSlice,
    22→  uiSlice,
    23→  overlaySlice,
    24→} from './slices';
    25→
    26→// =============================================================================
    27→// MMS Application Machine
    28→// =============================================================================
    29→
    30→/**
    31→ * Main application state machine.
    32→ *
    33→ * Usage in React components:
    34→ * ```tsx
    35→ * function TrainList() {
    36→ *   const { state, actions } = mmsMachine.useMachine('fleet');
    37→ *   return (
    38→ *     <ul>
    39→ *       {state.trains.map(train => (
    40→ *         <li key={train.id} onClick={() => actions.selectTrain(train.id)}>
    41→ *           {train.trainNumber}
    42→ *         </li>
    43→ *       ))}
    44→ *     </ul>
    45→ *   );
    46→ * }
    47→ * ```
    48→ */
    49→export const mmsMachine = createMachine({
    50→  id: 'mms',
    51→  slices: {
    52→    fleet: fleetSlice,
    53→    fleetApi: fleetAsyncSlice,
    54→    canvas: canvasSlice,
    55→    canvasData: canvasDataSlice,
    56→    pm: pmSlice,
    57→    pmApi: pmAsyncSlice,
    58→    scenario: scenarioSlice,
    59→    scenarioApi: scenarioAsyncSlice,
    60→    ui: uiSlice,
    61→    overlay: overlaySlice,
    62→  },
    63→  context: {
    64→    // User ID for private cache policy
    65→    userID: null as string | null,
    66→    // Context properties for async slices
    67→    baseUrl: '/api/v1',
    68→    startDate: new Date().toISOString().split('T')[0],
    69→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    70→  },
    71→});
    72→
    73→// =============================================================================
    74→// Type Exports
    75→// =============================================================================
    76→
    77→export type MmsMachine = typeof mmsMachine;
    78→export type MmsSliceId = keyof typeof mmsMachine extends infer K
    79→  ? K extends 'useMachine' | 'useSlice' | 'dispatch' | 'getState' | 'subscribe'
    80→    ? never
    81→    : K
    82→  : never;
    83→
    84→// =============================================================================
    85→// Re-exports
    86→// =============================================================================
    87→
    88→// Types
    89→export * from './types';
    90→
    91→// Slices
    92→export * from './slices';
    93→
    94→// Batch utilities
    95→export {
    96→  batchDispatch,
    97→  batchDispatches,
    98→  flushBatch,
    99→  cancelBatch,
   100→  getBatchStatus,
   101→  createBatchedDispatcher,
   102→  debouncedBatchDispatch,
   103→  throttledBatchDispatch,
   104→  createPointerMoveHandler,
   105→  createWheelHandler,
   106→} from './utils/batch';
   107→
   108→// =============================================================================
   109→// Convenience Hooks
   110→// =============================================================================
   111→
   112→/**
   113→ * Hook for fleet state and actions
   114→ *
   115→ * @example
   116→ * ```tsx
   117→ * function FleetView() {
   118→ *   const { state, actions } = useFleet();
   119→ *   return <div>{state.trains.length} trains</div>;
   120→ * }
