  1223→          entityType: 'fleet',
  1224→          entityId: fleetId,
  1225→        });
  1226→      }
  1227→
  1228→      // Get all stats in one query
  1229→      const statsQuery = await this.db
  1230→        .select({
  1231→          totalTrains: count(),
  1232→          totalMileageKm: sum(trains.currentMileageKm),
  1233→          averageMileageKm: avg(trains.currentMileageKm),
  1234→          minMileageKm: sql<number>`MIN(${trains.currentMileageKm})`,
  1235→          maxMileageKm: sql<number>`MAX(${trains.currentMileageKm})`,
