     2→/**
     3→ * MMS Development Server Orchestrator
     4→ *
     5→ * Starts all services needed for local development:
     6→ * - API Server (Hono) on PORT (default: 3000)
     7→ * - Frontend (Vite) with proxy to API
     8→ * - Workers (optional, set WORKERS env var)
     9→ *
    10→ * Usage:
    11→ *   bun run scripts/dev.ts           # Start API + Frontend
    12→ *   WORKERS=all bun run scripts/dev.ts  # Include all workers
    13→ *
    14→ * Environment Variables:
    15→ *   PORT          - API server port (default: 3000)
    16→ *   VITE_PORT     - Frontend port (default: 5173)
    17→ *   WORKERS       - Comma-separated worker list or 'all' (default: none)
    18→ *   VITE_API_URL  - Auto-set based on PORT
    19→ */
    20→
    21→import { spawn, type Subprocess } from 'bun';
    22→import { resolve } from 'path';
    23→
    24→const ROOT = resolve(import.meta.dir, '..');
    25→const API_PORT_ENV = process.env.PORT || '3000';
    26→const VITE_PORT = process.env.VITE_PORT || '5173';
    27→const WORKERS = process.env.WORKERS || '';
    28→
    29→const processes: Subprocess[] = [];
    30→let shuttingDown = false;
    31→let actualApiPort: string = API_PORT_ENV;
    32→
    33→function log(service: string, message: string, color: string = '\x1b[0m') {
    34→  const timestamp = new Date().toISOString().split('T')[1].slice(0, 8);
    35→  console.log(`${color}[${timestamp}] [${service}]\x1b[0m ${message}`);
    36→}
    37→
    38→const COLORS = {
    39→  api: '\x1b[36m',      // Cyan
    40→  frontend: '\x1b[35m', // Magenta
    41→  workers: '\x1b[33m',  // Yellow
    42→  system: '\x1b[32m',   // Green
    43→};
    44→
    45→interface ServiceResult {
    46→  proc: Subprocess;
    47→  portPromise?: Promise<string>;
    48→}
    49→
    50→async function startService(
    51→  name: string,
    52→  cmd: string[],
    53→  env: Record<string, string> = {},
    54→  color: string,
    55→  parsePort: boolean = false
    56→): Promise<ServiceResult> {
    57→  log(name, `Starting: ${cmd.join(' ')}`, color);
    58→
    59→  const proc = spawn({
    60→    cmd,
    61→    cwd: ROOT,
    62→    env: { ...process.env, ...env },
    63→    stdout: 'pipe',
    64→    stderr: 'pipe',
    65→  });
    66→
    67→  let portResolve: ((port: string) => void) | null = null;
    68→  const portPromise = parsePort
    69→    ? new Promise<string>((resolve) => {
    70→        portResolve = resolve;
    71→      })
    72→    : undefined;
    73→
    74→  // Stream stdout
    75→  (async () => {
    76→    const reader = proc.stdout.getReader();
    77→    const decoder = new TextDecoder();
    78→    while (true) {
    79→      const { done, value } = await reader.read();
    80→      if (done) break;
    81→      const lines = decoder.decode(value).split('\n').filter(Boolean);
    82→      for (const line of lines) {
    83→        log(name, line, color);
    84→        // Parse API_SERVER_PORT=XXXX from output
    85→        if (parsePort && portResolve) {
    86→          const match = line.match(/API_SERVER_PORT=(\d+)/);
    87→          if (match) {
    88→            portResolve(match[1]);
    89→            portResolve = null;
    90→          }
    91→        }
    92→      }
    93→    }
    94→  })();
    95→
    96→  // Stream stderr
    97→  (async () => {
    98→    const reader = proc.stderr.getReader();
    99→    const decoder = new TextDecoder();
   100→    while (true) {
   101→      const { done, value } = await reader.read();
   102→      if (done) break;
   103→      const lines = decoder.decode(value).split('\n').filter(Boolean);
   104→      for (const line of lines) {
   105→        log(name, `[stderr] ${line}`, color);
   106→      }
   107→    }
   108→  })();
   109→
   110→  processes.push(proc);
   111→  return { proc, portPromise };
   112→}
   113→
   114→async function shutdown(signal: string) {
   115→  if (shuttingDown) return;
   116→  shuttingDown = true;
   117→
   118→  log('system', `Received ${signal}, shutting down...`, COLORS.system);
   119→
   120→  for (const proc of processes) {
   121→    try {
   122→      proc.kill();
   123→    } catch {
   124→      // Process may have already exited
   125→    }
   126→  }
   127→
   128→  // Give processes time to cleanup
   129→  await new Promise((resolve) => setTimeout(resolve, 1000));
   130→
   131→  log('system', 'All services stopped', COLORS.system);
   132→  process.exit(0);
   133→}
   134→
   135→// Handle shutdown signals
   136→process.on('SIGINT', () => shutdown('SIGINT'));
   137→process.on('SIGTERM', () => shutdown('SIGTERM'));
   138→
   139→async function main() {
   140→  console.log('\n');
   141→  log('system', '='.repeat(60), COLORS.system);
   142→  log('system', 'MMS Development Server', COLORS.system);
   143→  log('system', '='.repeat(60), COLORS.system);
   144→  console.log('');
   145→
   146→  // Start API Server with port parsing enabled
   147→  const apiResult = await startService(
   148→    'api',
   149→    ['bun', 'run', 'src/api/server.ts'],
   150→    { PORT: API_PORT_ENV },
   151→    COLORS.api,
   152→    true // Parse actual port from output
   153→  );
   154→
   155→  // Wait for actual port (with timeout)
   156→  if (apiResult.portPromise) {
   157→    const timeoutPromise = new Promise<string>((_, reject) =>
   158→      setTimeout(() => reject(new Error('Timeout waiting for API port')), 10000)
   159→    );
   160→    try {
   161→      actualApiPort = await Promise.race([apiResult.portPromise, timeoutPromise]);
   162→      log('system', `API server detected on port ${actualApiPort}`, COLORS.system);
   163→    } catch {
   164→      log('system', `Warning: Could not detect API port, using ${API_PORT_ENV}`, COLORS.system);
   165→      actualApiPort = API_PORT_ENV;
   166→    }
   167→  }
   168→
   169→  // Start Workers (if requested)
   170→  if (WORKERS) {
   171→    await startService(
   172→      'workers',
   173→      ['bun', 'run', 'src/workers/runner.ts'],
   174→      { WORKERS },
   175→      COLORS.workers
   176→    );
   177→    await new Promise((resolve) => setTimeout(resolve, 500));
   178→  }
   179→
   180→  // Start Vite with proxy configured to actual API port
   181→  await startService(
   182→    'frontend',
   183→    ['bunx', 'vite'],
   184→    {
   185→      VITE_PORT,
   186→      VITE_API_URL: `http://localhost:${actualApiPort}`,
   187→    },
   188→    COLORS.frontend
   189→  );
   190→
   191→  console.log('');
   192→  log('system', '='.repeat(60), COLORS.system);
   193→  log('system', `API Server:  http://localhost:${actualApiPort}`, COLORS.system);
   194→  log('system', `Frontend:    http://localhost:${VITE_PORT}`, COLORS.system);
   195→  if (WORKERS) {
   196→    log('system', `Workers:     ${WORKERS === 'all' ? 'ALL' : WORKERS}`, COLORS.system);
   197→  }
   198→  log('system', '='.repeat(60), COLORS.system);
   199→  log('system', 'Press Ctrl+C to stop all services', COLORS.system);
   200→  console.log('');
   201→
   202→  // Keep process alive
   203→  await new Promise(() => {});
   204→}
   205→
   206→main().catch((error) => {
   207→  console.error('Failed to start development server:', error);
   208→  process.exit(1);
   209→});
