     1→#!/usr/bin/env bun
     2→/**
     3→ * MMS Demo Data Generator CLI
     4→ *
     5→ * Usage:
     6→ *   bun run src/demo/cli.ts [options]
     7→ *
     8→ * Options:
     9→ *   --trains <number>     Number of trains to generate (default: 128)
    10→ *   --history <years>     Years of historical data (default: 5)
    11→ *   --bow-wave            Enable bow-wave scenario (Q2 2027 clustering)
    12→ *   --seed <number>       Random seed for reproducible generation
    13→ *   --output <file>       Output SQL file (default: stdout)
    14→ *   --json                Output JSON instead of SQL
    15→ *   --analyze             Analyze bow-wave scenario and output report
    16→ *   --horizon <years>     Analysis horizon in years (default: 3)
    17→ *
    18→ * @example
    19→ *   bun run src/demo/cli.ts --trains 128 --bow-wave --output drizzle/manual/seed_demo.sql
    20→ *   bun run src/demo/cli.ts --trains 128 --bow-wave --analyze --json
    21→ */
    22→
    23→import { writeFileSync } from 'node:fs';
    24→import { generateDemoData, generateSQL } from './generator';
    25→import { analyzeBowWaveScenario, formatAnalysisReport } from './analyzer';
    26→
    27→interface CliArgs {
    28→  trains: number;
    29→  history: number;
    30→  bowWave: boolean;
    31→  seed?: number;
    32→  output?: string;
    33→  json: boolean;
    34→  analyze: boolean;
    35→  horizon: number;
    36→}
    37→
    38→function parseArgs(): CliArgs {
    39→  const args = process.argv.slice(2);
    40→  const result: CliArgs = {
    41→    trains: 128,
    42→    history: 5,
    43→    bowWave: false,
    44→    json: false,
    45→    analyze: false,
    46→    horizon: 3,
    47→  };
    48→
    49→  for (let i = 0; i < args.length; i++) {
    50→    const arg = args[i];
    51→
    52→    switch (arg) {
    53→      case '--trains':
    54→        result.trains = parseInt(args[++i], 10);
    55→        break;
    56→      case '--history':
    57→        result.history = parseInt(args[++i], 10);
    58→        break;
    59→      case '--bow-wave':
    60→        result.bowWave = true;
    61→        break;
    62→      case '--seed':
    63→        result.seed = parseInt(args[++i], 10);
    64→        break;
    65→      case '--output':
    66→        result.output = args[++i];
    67→        break;
    68→      case '--json':
    69→        result.json = true;
    70→        break;
    71→      case '--analyze':
    72→        result.analyze = true;
    73→        break;
    74→      case '--horizon':
    75→        result.horizon = parseInt(args[++i], 10);
    76→        break;
    77→      case '--help':
    78→      case '-h':
    79→        console.log(`
    80→MMS Demo Data Generator
    81→
    82→Usage:
    83→  bun run src/demo/cli.ts [options]
    84→
    85→Options:
    86→  --trains <number>     Number of trains to generate (default: 128)
    87→  --history <years>     Years of historical data (default: 5)
    88→  --bow-wave            Enable bow-wave scenario (Q2 2027 clustering)
    89→  --seed <number>       Random seed for reproducible generation
    90→  --output <file>       Output SQL file (default: stdout)
    91→  --json                Output JSON instead of SQL
    92→  --analyze             Analyze bow-wave scenario and output report
    93→  --horizon <years>     Analysis horizon in years (default: 3)
    94→  --help, -h            Show this help message
    95→
    96→Examples:
    97→  # Generate 128-train demo data with bow-wave scenario
    98→  bun run src/demo/cli.ts --trains 128 --bow-wave --output drizzle/manual/seed_demo.sql
    99→
   100→  # Generate reproducible data with specific seed
   101→  bun run src/demo/cli.ts --seed 12345 --output seed.sql
   102→
   103→  # Generate JSON for API testing
   104→  bun run src/demo/cli.ts --json > demo-data.json
   105→
   106→  # Analyze bow-wave scenario (human-readable report)
   107→  bun run src/demo/cli.ts --trains 128 --bow-wave --analyze
   108→
   109→  # Analyze and output JSON for visualization
   110→  bun run src/demo/cli.ts --trains 128 --bow-wave --analyze --json
   111→`);
   112→        process.exit(0);
   113→    }
   114→  }
   115→
   116→  return result;
   117→}
   118→
   119→function main(): void {
   120→  const args = parseArgs();
   121→
   122→  console.error(`Generating demo data...`);
   123→  console.error(`  Trains: ${args.trains}`);
   124→  console.error(`  History: ${args.history} years`);
   125→  console.error(`  Bow-wave: ${args.bowWave ? 'enabled' : 'disabled'}`);
   126→  console.error(`  Analyze: ${args.analyze ? 'enabled' : 'disabled'}`);
   127→  if (args.analyze) {
   128→    console.error(`  Horizon: ${args.horizon} years`);
   129→  }
   130→  if (args.seed !== undefined) {
   131→    console.error(`  Seed: ${args.seed}`);
   132→  }
   133→
   134→  const startTime = Date.now();
   135→
   136→  const data = generateDemoData({
   137→    trainCount: args.trains,
   138→    historyYears: args.history,
   139→    enableBowWave: args.bowWave,
   140→    seed: args.seed,
   141→  });
   142→
   143→  const genTime = Date.now() - startTime;
   144→  console.error(`\nGeneration complete in ${genTime}ms`);
   145→  console.error(`  Depots: ${data.depots.length}`);
   146→  console.error(`  Fleets: ${data.fleets.length}`);
   147→  console.error(`  Trains: ${data.trains.length}`);
   148→  console.error(`  PM Types: ${data.pmTypes.length}`);
   149→  console.error(`  PM History: ${data.pmHistory.length}`);
   150→  console.error(`  Mileage Readings: ${data.mileageReadings.length}`);
   151→  console.error(`  Service Demand: ${data.serviceDemand.length}`);
   152→  console.error(`  Tracks: ${data.tracks.length}`);
   153→
   154→  let output: string;
   155→
   156→  if (args.analyze) {
   157→    // Run bow-wave analysis
   158→    console.error(`\nAnalyzing bow-wave scenario...`);
   159→    const analysisStartTime = Date.now();
   160→
   161→    const analysisOutput = analyzeBowWaveScenario(data, { horizonYears: args.horizon });
   162→
   163→    const analysisTime = Date.now() - analysisStartTime;
   164→    console.error(`Analysis complete in ${analysisTime}ms`);
   165→    console.error(`  Projected PMs: ${analysisOutput.projectedPMs.length}`);
   166→    console.error(`  Critical Months: ${analysisOutput.monthlyDensity.filter((m) => m.isCritical).length}`);
   167→    console.error(`  Risk Level: ${analysisOutput.analysis.riskLevel}`);
   168→
   169→    if (args.json) {
   170→      // Convert dates to ISO strings for JSON serialization
   171→      const jsonOutput = {
   172→        ...analysisOutput,
   173→        projectedPMs: analysisOutput.projectedPMs.map((pm) => ({
   174→          ...pm,
   175→          projectedDate: pm.projectedDate.toISOString().split('T')[0],
   176→        })),
   177→      };
   178→      output = JSON.stringify(jsonOutput, null, 2);
   179→    } else {
   180→      output = formatAnalysisReport(analysisOutput);
   181→    }
   182→  } else if (args.json) {
   183→    // Convert dates to ISO strings for JSON serialization
   184→    const jsonData = {
   185→      ...data,
   186→      trains: data.trains.map((t) => ({
   187→        ...t,
   188→        commissioningDate: t.commissioningDate.toISOString().split('T')[0],
   189→      })),
   190→      pmHistory: data.pmHistory.map((pm) => ({
   191→        ...pm,
   192→        completionDate: pm.completionDate.toISOString().split('T')[0],
   193→      })),
   194→      mileageReadings: data.mileageReadings.map((r) => ({
   195→        ...r,
   196→        readingDate: r.readingDate.toISOString().split('T')[0],
   197→      })),
   198→    };
   199→    output = JSON.stringify(jsonData, null, 2);
   200→  } else {
   201→    output = generateSQL(data);
   202→  }
   203→
   204→  if (args.output) {
   205→    writeFileSync(args.output, output);
   206→    console.error(`\nOutput written to: ${args.output}`);
   207→  } else {
   208→    console.log(output);
   209→  }
   210→}
   211→
   212→main();
